/**
 * Smart search: tokenize query, score each tradition by keyword overlap,
 * return best match or fallback if score is too low.
 */
export function searchAIResponse(query: string): AIResponse {
  const normalize = (s: string) =>
    s
      .toLowerCase()
      .replace(/[^a-z0-9 ]/g, " ")
      .split(/\s+/)
      .filter(Boolean);

  const queryTokens = normalize(query);
  if (queryTokens.length === 0) return fallbackResponse;

  let bestMatch: AIResponse | null = null;
  let bestScore = 0;

  for (const item of aiResponses) {
    const searchableText = [
      item.tradition,
      ...item.tags,
      item.background.slice(0, 300),
    ]
      .join(" ")
      .toLowerCase();

    let score = 0;
    for (const token of queryTokens) {
      if (token.length < 3) continue;
      if (searchableText.includes(token)) {
        // Higher weight for tag or tradition matches
        if (item.tags.some((t) => t.includes(token) || token.includes(t))) {
          score += 3;
        } else if (item.tradition.toLowerCase().includes(token)) {
          score += 5;
        } else {
          score += 1;
        }
      }
    }

    if (score > bestScore) {
      bestScore = score;
      bestMatch = item;
    }
  }

  // Return matched tradition (with the user's original query as tradition name for display)
  // but only if score is meaningful
  if (bestMatch && bestScore >= 2) {
    return bestMatch;
  }

  return fallbackResponse;
}
